import{c as t,Q as a,j as n,m as i}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Instances","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/instances.md","filePath":"guide/admin/instances.md","lastUpdated":1779094756000}'),o={name:"guide/admin/instances.md"};function r(s,e,l,d,c,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="instances" tabindex="-1">Instances <a class="header-anchor" href="#instances" aria-label="Permalink to &quot;Instances&quot;">​</a></h1><p>The <strong>Instances</strong> page manages the fleet of hosted environments that run tenants. Each instance is typically a Kubernetes cluster or hosted backend.</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><ul><li><strong>Search</strong> — matches instance name or any tag key/value.</li><li><strong>Status</strong> — All / Active / Provisioning / Inactive / Decommissioned.</li><li><strong>Environment</strong> — filter by env tag value.</li><li><strong>Region</strong> — filter by region tag value.</li><li><strong>Clear</strong> — appears when any filter is active.</li><li><strong>New Instance</strong> button (top right).</li><li>Count chip — filtered vs. total.</li></ul><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Clickable link to instance detail.</td></tr><tr><td><strong>Tags</strong></td><td>Key:value chips.</td></tr><tr><td><strong>Status</strong></td><td>Active (green) / Provisioning (orange) / Inactive (grey) / Decommissioned (red).</td></tr><tr><td><strong>Tenants</strong></td><td>Capacity utilisation, e.g. &quot;50 / 100&quot;.</td></tr><tr><td><strong>Last Heartbeat</strong></td><td>Relative timestamp from the agent&#39;s last check-in.</td></tr><tr><td><strong>Actions</strong></td><td>Edit / Decommission / Delete.</td></tr></tbody></table><h2 id="creating-a-new-instance" tabindex="-1">Creating a new instance <a class="header-anchor" href="#creating-a-new-instance" aria-label="Permalink to &quot;Creating a new instance&quot;">​</a></h2><p>Click <strong>New Instance</strong>. The modal has these sections:</p><h3 id="basics-required" tabindex="-1">Basics (required) <a class="header-anchor" href="#basics-required" aria-label="Permalink to &quot;Basics (required)&quot;">​</a></h3><ul><li><strong>Name</strong> — display name.</li><li><strong>API Base URL</strong> — the instance&#39;s API root, used by the Console.</li><li><strong>MongoDB URI</strong> — connection string for the instance&#39;s data plane.</li><li><strong>Max Tenants</strong> — hard cap on tenant count.</li><li><strong>Health Check URL</strong> — optional override; the agent&#39;s default is used if blank.</li></ul><h3 id="oidc-redirect-uris" tabindex="-1">OIDC Redirect URIs <a class="header-anchor" href="#oidc-redirect-uris" aria-label="Permalink to &quot;OIDC Redirect URIs&quot;">​</a></h3><p>A list of allowed OAuth redirect URIs. Defaults shown can be edited.</p><h3 id="environment-region" tabindex="-1">Environment &amp; Region <a class="header-anchor" href="#environment-region" aria-label="Permalink to &quot;Environment &amp; Region&quot;">​</a></h3><ul><li><strong>Environment</strong> — DEV / QA / UAT / STAGING / DEMO / PRE_PROD / PROD.</li><li><strong>Region</strong> — Azure region.</li></ul><h3 id="pipeline" tabindex="-1">Pipeline <a class="header-anchor" href="#pipeline" aria-label="Permalink to &quot;Pipeline&quot;">​</a></h3><ul><li><strong>Exclude from pipeline</strong> toggle. When on, the instance is skipped by automated CI/CD branch deployment and only receives explicit docker-tag deploys.</li></ul><h3 id="tags" tabindex="-1">Tags <a class="header-anchor" href="#tags" aria-label="Permalink to &quot;Tags&quot;">​</a></h3><p>Key-value editor for free-form metadata.</p><p>Click <strong>Create</strong>.</p><h3 id="provisioning-credentials" tabindex="-1">Provisioning credentials <a class="header-anchor" href="#provisioning-credentials" aria-label="Permalink to &quot;Provisioning credentials&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Screenshot</p><p><em>Provisioning credentials reveal:</em> the post-create state of the modal showing the four credential values and the &quot;copy these now&quot; warning. <strong>High value</strong> — this is the one screen operators must not miss.</p></div><p>After creation the modal flips to show the provisioning credentials:</p><ul><li><code>CONSOLE_INSTANCE_TOKEN</code></li><li><code>CONSOLE_INSTANCE_ID</code></li><li><code>CONSOLE_CLIENT_ID</code></li><li><code>EXTOID_PROJECT_ID</code></li></ul><blockquote><p><strong>Copy these now.</strong> The token will never be shown again. Store them as a Kubernetes secret on the target cluster and deploy the Console agent there. The instance stays in <code>provisioning</code> status until the agent reports in.</p></blockquote><h2 id="editing-an-instance" tabindex="-1">Editing an instance <a class="header-anchor" href="#editing-an-instance" aria-label="Permalink to &quot;Editing an instance&quot;">​</a></h2><p>The pencil icon opens an edit modal with a subset of fields: Name, Environment, Exclude from pipeline, Max Tenants, Health Check URL, Tags. API URL and MongoDB URI are not editable here — they are set once at creation.</p><h2 id="decommissioning" tabindex="-1">Decommissioning <a class="header-anchor" href="#decommissioning" aria-label="Permalink to &quot;Decommissioning&quot;">​</a></h2><p>The power icon opens a confirmation dialog. Decommissioning <strong>cannot be undone</strong>. Tenants on the instance must be migrated or deleted first.</p><h2 id="deleting" tabindex="-1">Deleting <a class="header-anchor" href="#deleting" aria-label="Permalink to &quot;Deleting&quot;">​</a></h2><p>The trash icon opens a confirmation dialog. Delete is a hard removal and is typically reserved for instances that were never put into service.</p><h2 id="instance-detail-page" tabindex="-1">Instance detail page <a class="header-anchor" href="#instance-detail-page" aria-label="Permalink to &quot;Instance detail page&quot;">​</a></h2><h3 id="header" tabindex="-1">Header <a class="header-anchor" href="#header" aria-label="Permalink to &quot;Header&quot;">​</a></h3><p>Instance name, environment tag, and action buttons.</p><h3 id="tabs" tabindex="-1">Tabs <a class="header-anchor" href="#tabs" aria-label="Permalink to &quot;Tabs&quot;">​</a></h3><h4 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h4><ul><li><strong>Details</strong> card — Name, Environment, API URL, Database URL, Max Tenants, Health Check URL, Exclude from Pipeline. Click Edit for inline editing.</li><li><strong>Services Health</strong> widget — rolled-up status, list of running services with status dot, version, replica counts, restart count, and last deployed time. Colour reflects state: green all healthy, red all unavailable, orange mixed, grey no data.</li></ul><h4 id="tenants" tabindex="-1">Tenants <a class="header-anchor" href="#tenants" aria-label="Permalink to &quot;Tenants&quot;">​</a></h4><p>The tenants currently provisioned on this instance, with quick navigation to each.</p><h4 id="jobs" tabindex="-1">Jobs <a class="header-anchor" href="#jobs" aria-label="Permalink to &quot;Jobs&quot;">​</a></h4><p>Migration jobs that target this instance — clones, deletes, imports, instance replaces. Status, start time, duration.</p><h4 id="insights" tabindex="-1">Insights <a class="header-anchor" href="#insights" aria-label="Permalink to &quot;Insights&quot;">​</a></h4><p>Time-series usage for the instance.</p><ul><li>Date range toggle — 7d / 30d / 90d.</li><li>Usage meters — CPU, Memory, Disk.</li><li>Charts for each metric.</li></ul><h4 id="spocs" tabindex="-1">SPOCs <a class="header-anchor" href="#spocs" aria-label="Permalink to &quot;SPOCs&quot;">​</a></h4><p>Single Points of Contact for this instance — used by the release pipeline&#39;s approval flow. Add or remove SPOCs here.</p><h4 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;Services&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">Screenshot</p><p><em>Services tab with drift:</em> the service list with at least one row showing <strong>environment drift</strong> (expected vs. actual values), and an expanded row revealing per-variable Set/Remove Override controls.</p></div><p>The full service catalogue for the instance, with a managed-vs-all toggle.</p><ul><li><strong>Managed</strong> — services declared in the <a href="./release-configuration">Release Configuration</a>. These are the ones the pipeline operates on.</li><li><strong>All</strong> — managed plus any other discovered service pods.</li></ul><p>Per-service rows show name, image, version, replicas (ready / desired), status dot, restart count, last deployed.</p><p><strong>Environment drift</strong> is detected and surfaced: if the agent reports a variable value different from what the Console resolved, the row is highlighted with an &quot;expected vs. actual&quot; view.</p><p>Expand a row to see its full environment-variable list. Each variable can be <strong>overridden</strong> at the instance level:</p><ul><li><strong>Set Override</strong> — opens a modal to enter a value or a secret reference (<code>name/key</code>).</li><li><strong>Remove Override</strong> — drops back to the global default.</li></ul><p>A warning banner appears if a managed service is configured but no pods are reporting.</p>',55)])])}const p=t(o,[["render",r]]);export{u as __pageData,p as default};
